}

function closeWindow(app) {
  const winId = app === 'files' ? 'files-window' : 'notepad-window';
  document.getElementById(winId).style.display = 'none';
  updateLauncherState();
}

function focusWindow(win) {
  document.querySelectorAll('.window').forEach(w => w.classList.remove('focused'));
  win.classList.add('focused');
}

function updateLauncherState() {
  const filesWin = document.getElementById('files-window');
  const notepadWin = document.getElementById('notepad-window');
  document.getElementById('open-files').classList.toggle('active', filesWin.style.display !== 'none');
  document.getElementById('open-notepad').classList.toggle('active', notepadWin.style.display !== 'none');
}

// ═══════════════════════════════════════════
//  DRAGGABLE WINDOWS
// ═══════════════════════════════════════════
let dragState = null;

document.querySelectorAll('.window-header').forEach(header => {
  header.addEventListener('mousedown', (e) => {
    if (e.target.classList.contains('win-ctrl')) return;
    const win = header.parentElement;
    focusWindow(win);

    const rect = win.getBoundingClientRect();
    dragState = {
      win: win,
      offsetX: e.clientX - rect.left,
      offsetY: e.clientY - rect.top
    };
    e.preventDefault();
  });
});

document.addEventListener('mousemove', (e) => {
  if (!dragState) return;
  const x = e.clientX - dragState.offsetX;
  const y = e.clientY - dragState.offsetY;
  dragState.win.style.left = Math.max(0, x) + 'px';
  dragState.win.style.top = Math.max(28, y) + 'px';
});

document.addEventListener('mouseup', () => {
  dragState = null;
});

// Click on window to focus
document.querySelectorAll('.window').forEach(win => {
  win.addEventListener('mousedown', () => focusWindow(win));
});

